def filter_grayscale(raster: Raster) -> Raster:
    source = raster.to_rgb()
    output = bytearray(len(source.data))
    for index in range(0, len(source.data), 3):
        gray = _luminance(source.data[index], source.data[index + 1], source.data[index + 2])
        output[index : index + 3] = bytes((gray, gray, gray))
    return Raster(source.width, source.height, 3, output)

