def filter_invert(raster: Raster) -> Raster:
    source = raster.to_rgb()
    output = bytearray(len(source.data))
    for index in range(len(source.data)):
        output[index] = 255 - source.data[index]
    return Raster(source.width, source.height, 3, output)

