def _box_blur_channel(values: list[float], width: int, height: int, radius: int) -> list[float]:
    if radius <= 0:
        return values
    diameter = radius * 2 + 1
    area = diameter * diameter
    output = [0.0] * len(values)
    for row in range(height):
        for col in range(width):
            total = 0.0
            for offset_y in range(-radius, radius + 1):
                sample_y = min(height - 1, max(0, row + offset_y))
                for offset_x in range(-radius, radius + 1):
                    sample_x = min(width - 1, max(0, col + offset_x))
                    total += values[sample_y * width + sample_x]
            output[row * width + col] = total / area
    return output

