def filter_sharpen(raster: Raster, amount: float = 1.0) -> Raster:
    source = raster.to_rgb()
    blurred = filter_blur(source, radius=1)
    output = bytearray(len(source.data))
    for index in range(len(source.data)):
        delta = source.data[index] - blurred.data[index]
        output[index] = int(max(0, min(255, source.data[index] + amount * delta)))
    return Raster(source.width, source.height, 3, output)

