def apply_filter(raster: Raster, filter_name: str) -> Raster:
    normalized = (filter_name or "none").strip().lower()
    handler = FILTERS.get(normalized)
    if handler is None:
        raise ValueError(f"Unknown filter: {filter_name}")
    return handler(raster)

