def _draw_text(
    raster: Raster,
    text: str,
    start_x: int,
    start_y: int,
    color: tuple[int, int, int],
    alpha: float,
) -> None:
    cursor_x = start_x
    for character in text:
        glyph = _GLYPHS.get(character)
        if glyph is None:
            cursor_x += _GLYPH_WIDTH + _GLYPH_SPACING
            continue

        for row in range(_GLYPH_HEIGHT):
            for col in range(_GLYPH_WIDTH):
                if glyph[row][col] != "1":
                    continue
                x = cursor_x + col
                y = start_y + row
                if not (0 <= x < raster.width and 0 <= y < raster.height):
                    continue
                pixel_index = (y * raster.width + x) * 3
                for channel in range(3):
                    base = raster.data[pixel_index + channel]
                    target = color[channel]
                    raster.data[pixel_index + channel] = int(base * (1 - alpha) + target * alpha)

        cursor_x += _GLYPH_WIDTH + _GLYPH_SPACING
